    quiz: [
      { question: "What does DCIS mean?", correctAnswer: "Ductal carcinoma in situ", distractors: ["Direct cancer invasion site", "Diagnostic core imaging study", "Distal cyst in situ"] },
      { question: "What is triple assessment?", correctAnswer: "Clinical examination, imaging and biopsy together", distractors: ["Three separate consultant opinions", "Three rounds of chemotherapy", "Three follow-up appointments"] },
      { question: "What does SLNB mean?", correctAnswer: "Sentinel lymph node biopsy", distractors: ["Surgical lymph node biopsy", "Single lobe needle biopsy", "Subcutaneous lymph node block"] },
      { question: "What is a mastectomy?", correctAnswer: "Removal of breast tissue", distractors: ["Removal of a breast lump only", "Removal of lymph nodes only", "Reconstruction of the breast"] },
      { question: "What does 'clear margins' mean in a histology report?", correctAnswer: "No abnormal cells found at the edge of the removed specimen", distractors: ["Cancer was found at the edge of the specimen", "The specimen was too small to assess", "Further imaging is required"] },
      { question: "What is the difference between IDC and ILC?", correctAnswer: "IDC is invasive ductal carcinoma; ILC is invasive lobular carcinoma — different types of invasive breast cancer", distractors: ["They are two names for the same condition", "IDC is benign, ILC is malignant", "ILC only affects the lymph nodes"] },
      { question: "What does a 2 Week Wait referral mean?", correctAnswer: "An urgent suspected cancer referral requiring rapid assessment", distractors: ["A routine referral with no time pressure", "A referral only used for benign lumps", "A referral that applies only to follow-up appointments"] },
      { question: "What is the purpose of hormone therapy such as Tamoxifen?", correctAnswer: "To treat hormone-sensitive breast cancers", distractors: ["To treat all types of breast cancer regardless of receptor status", "To replace the need for surgery", "To prevent post-operative infection"] },
      { question: "What does HER2 status affect?", correctAnswer: "Whether targeted therapy may be suitable for the patient's cancer", distractors: ["Only the choice of imaging used", "Only whether surgery is needed", "Only the patient's eligibility for screening"] },
      { question: "What is axillary clearance?", correctAnswer: "Removal of lymph nodes from the armpit area", distractors: ["Removal of the entire breast", "A type of imaging investigation", "A non-surgical cancer treatment"] },
      { question: "What should a secretary check before confirming a breast surgery theatre booking?", correctAnswer: "Procedure type, side/laterality, histology availability, MDT outcome, insurance approval and follow-up", distractors: ["Only the consultant's diary availability", "Only the patient's home address", "Only the GP's contact details"] },
      { question: "What does 'positive nodes' mean in a results letter?", correctAnswer: "Cancer cells have been found in the lymph nodes", distractors: ["No abnormality was found in the lymph nodes", "The lymph nodes were not tested", "The patient tested positive for a genetic mutation"] },
      { question: "What is the purpose of an MRI breast scan?", correctAnswer: "To provide detailed imaging of the breast, often used alongside mammography and ultrasound", distractors: ["To replace the need for biopsy", "It is only used after surgery", "It is only used for screening, never diagnosis"] },
      { question: "What does BRCA gene mutation relate to?", correctAnswer: "An increased genetic risk of developing breast cancer", distractors: ["A type of breast reconstruction technique", "A grading system for tumour size", "A medication used in chemotherapy"] },
      { question: "What is breast reconstruction?", correctAnswer: "Surgery to rebuild the shape of the breast, often after mastectomy", distractors: ["A type of breast cancer screening", "A non-surgical hormone treatment", "A biopsy technique"] },
    ],
